 const exportJson=()=>{const payload={schema:'mid-favorites',version:3,exportedAt:new Date().toISOString(),locationTrackingFirst:locationTracking,favorites};const blob=new Blob([JSON.stringify(payload,null,2)],{type:'application/json'}),url=URL.createObjectURL(blob),anchor=document.createElement('a');anchor.href=url;anchor.download='mid-favoriten.json';anchor.click();setTimeout(()=>URL.revokeObjectURL(url),1000)};
